DRAFT — REQUIRES LEGAL REVIEW BEFORE SENDING

Subject: Important Notice Regarding Your {Company Name} Account

We are writing to inform you of an incident that may have affected
your account data.

What happened: {factual_description_of_event}

What information was involved: {data_categories_involved}

What we are doing: {remediation_steps}

What you can do: {recommended_user_actions}

For questions, contact: {data_protection_contact}

--- Notes ---
- Do not send until legal confirms the notification obligation and timing
- Confirm the specific data categories with the security team
- Include specific regulatory body contact info if required by jurisdiction
- Log the notification time for regulatory compliance records

from enum import Enum
from string import Template
from pathlib import Path
import json

class CommsTemplate(Enum):
    INVESTIGATING = 'template_a_investigating'
    IDENTIFIED = 'template_b_identified'
    RESOLVED = 'template_c_resolved'
    OUTPUT_QUALITY = 'template_d_quality'
    DATA_EXPOSURE = 'template_e_data_exposure'

    @property
    def requires_legal(self) -> bool:
        return self == CommsTemplate.DATA_EXPOSURE


class IncidentCommsLibrary:
    def __init__(self, template_dir: str = 'runbooks/comms-templates'):
        self.template_dir = Path(template_dir)

    def get_template(self, template: CommsTemplate) -> str:
        path = self.template_dir / f'{template.value}.txt'
        return path.read_text(encoding='utf-8')

    def render(
        self,
        template: CommsTemplate,
        variables: dict[str, str],
        strict: bool = True,
    ) -> str:
        """Render template with provided variables.

        In strict mode, raises KeyError for any unfilled placeholder.
        In non-strict mode, leaves unfilled placeholders for manual edit.
        """
        raw = self.get_template(template)
        if strict:
            return Template(raw).substitute(variables)
        return Template(raw).safe_substitute(variables)

    def validate_required_fields(
        self, template: CommsTemplate, variables: dict
    ) -> list[str]:
        """Return list of missing required field names."""
        raw = self.get_template(template)
        placeholders = {m.group(1) for m in __import__('re').finditer(r'\$\{?(\w+)\}?', raw)}
        return [p for p in placeholders if p not in variables]
